#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        double num1, num2, result;
        char op;
        scanf("%lf %lf", &num1, &num2);
        scanf(" %c", &op); // skip whitespace
        switch (op) {
            case '+': result = num1 + num2; break;
            case '-': result = num1 - num2; break;
            case '*': result = num1 * num2; break;
            case '/': result = num1 / num2; break;
            default:  result = 0; // never reached
        }
        printf("%.2f\n", result);
    }
    return 0;
}

