int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T;
    if (!(cin >> T)) return 0;
    while (T--) {
        double num1, num2, result;
        char op;
        cin >> num1 >> num2 >> op;
        switch (op) {
            case '+': result = num1 + num2; break;
            case '-': result = num1 - num2; break;
            case '*': result = num1 * num2; break;
            case '/': result = num1 / num2; break;
            default:  result = 0; break;
        }
        cout.setf(ios::fixed);
        cout << setprecision(2) << result << '\n';
    }
    return 0;
}

